<?php require_once __DIR__ . '/../includes/admin.php'; admin_required(); $error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);try{$projectId=filter_input(INPUT_POST,'project_id',FILTER_VALIDATE_INT)?:null;$image=upload_image($_FILES['image']??[],'gallery');db()->prepare('INSERT INTO gallery (project_id,image) VALUES (?,?)')->execute([$projectId,$image]);redirect('admin/gallery.php');}catch(Throwable $e){$error=$e->getMessage();}}$projects=db()->query('SELECT id,project_name FROM projects ORDER BY project_name')->fetchAll();$images=db()->query('SELECT g.*,p.project_name FROM gallery g LEFT JOIN projects p ON p.id=g.project_id ORDER BY g.uploaded_at DESC')->fetchAll();admin_head('Gallery'); ?><h1>Gallery</h1><form class="card" method="post" enctype="multipart/form-data"><h2>Upload image</h2><?php if($error):?><p class="error"><?=e($error)?></p><?php endif?><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Project (optional)</label><select name="project_id"><option value="">General gallery</option><?php foreach($projects as $p):?><option value="<?=$p['id']?>"><?=e($p['project_name'])?></option><?php endforeach?></select><input type="file" name="image" accept="image/jpeg,image/png,image/webp,image/gif" required><button>Upload image</button></form><div class="card"><table><tr><th>Image</th><th>Project</th><th>Date</th><th></th></tr><?php foreach($images as $image):?><tr><td><img class="thumb" src="<?=url($image['image'])?>" alt=""></td><td><?=e($image['project_name']??'General')?></td><td><?=e($image['uploaded_at'])?></td><td><form method="post" action="<?=url('admin/delete-gallery.php')?>"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$image['id']?>"><button class="danger" onclick="return confirm('Delete this image?')">Delete</button></form></td></tr><?php endforeach?></table></div><?php admin_foot(); ?>
